0.2 1. Core Architecture (UML Package Structure)
@startuml
!theme plain

package "projectaria_tools.core" {
  [calibration] --&gt; [sophus]
  [data_provider] --&gt; [calibration]
  [data_provider] --&gt; [sensor_data]
  [mps] --&gt; [sophus]
  [image]
}

package "projectaria_tools.projects.ase" {
  [readers] --&gt; [core.sophus]
  [readers] --&gt; [core.mps]
  [interpreter]
}

package "projectaria_tools.tools" {
  [aria_rerun_viewer] --&gt; [core]
  [dataset_downloader]
  [vrs_to_mp4] --&gt; [core]
}

@enduml
Key Packages:

core: Fundamental data structures (SE3, calibration, data provider)
projects.ase: ASE dataset readers and interpreters
tools: High-level utilities (downloading, visualization)
